#!/usr/bin/env node
require('dotenv').config({ path: '.env' });
const mongoose = require('mongoose');

const MONGO = process.env.MONGODB_URI || 'mongodb://localhost:27017/monnayeur';

async function run() {
    try {
        await mongoose.connect(MONGO, { useNewUrlParser: true, useUnifiedTopology: true });
        console.log('Connected to MongoDB', MONGO);
        const Transaction = require('../src/models/transaction.model');
        const docs = await Transaction.find({ orangeMerchantCode: '614841' }).sort({ createdAt: -1 }).limit(10).lean();
        console.log('Found', docs.length, 'transactions for merchant 614841');
        docs.forEach(d => {
            console.log('---');
            console.log('transactionId:', d.transactionId);
            console.log('status:', d.status);
            console.log('amountFcfa:', d.amountFcfa);
            console.log('orangeTransactionId:', d.orangeTransactionId);
            console.log('paidAt:', d.paidAt);
            console.log('createdAt:', d.createdAt);
            console.log('orangeCallbackPayload:', JSON.stringify(d.orangeCallbackPayload));
        });
    } catch (err) {
        console.error('Error', err.message || err);
    } finally {
        await mongoose.disconnect();
    }
}

run();

#!/usr/bin/env node

require("dotenv").config();

const orange = require("../src/services/orange.service");

async function main() {
    const mode = (process.argv[2] || "status").toLowerCase();

    if (mode === "token") {
        const result = await orange.getAccessToken();
        console.log(JSON.stringify(result, null, 2));
        process.exit(result.success ? 0 : 1);
    }

    if (mode === "qrcode") {
        const result = await orange.createMerchantQrCode({
            code: process.env.ORANGE_TEST_MERCHANT_CODE || "123456",
            name: process.env.ORANGE_TEST_MERCHANT_NAME || "Test Merchant",
            amount: Number(process.env.ORANGE_TEST_AMOUNT || 100),
            callbackUrl: process.env.ORANGE_CALLBACK_URL || "https://example.com/api/orange/webhook/merchant-payment"
        });
        console.log(JSON.stringify(result, null, 2));
        process.exit(result.success ? 0 : 1);
    }

    console.log(JSON.stringify({
        success: true,
        hasClientId: Boolean(process.env.ORANGE_CLIENT_ID),
        hasClientSecret: Boolean(process.env.ORANGE_CLIENT_SECRET),
        hasApiKey: Boolean(process.env.ORANGE_API_KEY),
        baseUrl: process.env.ORANGE_BASE_URL || process.env.ORANGE_API_BASE_URL || "https://api.sandbox.orange-sonatel.com"
    }, null, 2));
}

main().catch((error) => {
    console.error(error);
    process.exit(1);
});

#!/usr/bin/env node
require('dotenv').config({ path: '.env' });
const mongoose = require('mongoose');

const MONGO = process.env.MONGODB_URI || 'mongodb://localhost:27017/monnayeur';
const TARGET_MACHINE_ID = process.argv[2] || 'MACHINE_001';
const MERCHANT_CODE = process.argv[3] || process.env.ORANGE_MERCHANT_CODE || '614841';
const MERCHANT_NAME = process.argv[4] || process.env.ORANGE_MERCHANT_NAME || 'Machine 1';
const CALLBACK_URL = process.argv[5] || process.env.ORANGE_CALLBACK_URL || null;

(async function(){
  try{
    await mongoose.connect(MONGO);
    console.log('Connected to MongoDB', MONGO);
    const Machine = require('../src/models/machine.model');
    const machine = await Machine.findOne({ machineId: TARGET_MACHINE_ID });
    if(!machine){
      console.log('Machine', TARGET_MACHINE_ID, 'not found. Aborting.');
      return;
    }
    machine.orangeMerchantCode = String(MERCHANT_CODE).trim();
    machine.orangeMerchantName = MERCHANT_NAME;
    if(CALLBACK_URL) machine.orangeCallbackUrl = CALLBACK_URL;
    await machine.save();
    console.log('Updated machine:', { machineId: machine.machineId, orangeMerchantCode: machine.orangeMerchantCode, orangeCallbackUrl: machine.orangeCallbackUrl });
  }catch(err){
    console.error('Error', err.message || err);
  }finally{
    await mongoose.disconnect();
  }
})();

